input.style:
position: absolute;
top: 0; left: 0;
width: 100%; height: 100%;
opacity: 0;
cursor: pointer;
z-index: 10;

t.script:

document.addEventListener('DOMContentLoaded', function () {

    // The real file input that the browser submits natively
    const attachmentInput = document.getElementById('attachment');
    const attachmentDropArea = document.getElementById('attachmentDropArea');
    const fileList = document.getElementById('fileList');

    // --------------------------------------------------------
    // File change handler — update the visual preview list.
    // NOTE: We no longer maintain a separate selectedFiles array
    // or use DataTransfer. We read directly from input.files so
    // the preview always matches what will actually be submitted.
    // --------------------------------------------------------
    attachmentInput.addEventListener('change', function () {
        updateFileList(Array.from(this.files));
    });

    // --------------------------------------------------------
    // Drag-and-drop: prevent browser from navigating to the file
    // --------------------------------------------------------
    ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(function (eventName) {
        attachmentDropArea.addEventListener(eventName, function (e) {
            e.preventDefault();
            e.stopPropagation();
        });
    });

    attachmentDropArea.addEventListener('dragenter', function () {
        attachmentDropArea.classList.add('dragover');
    });
    attachmentDropArea.addEventListener('dragover', function () {
        attachmentDropArea.classList.add('dragover');
    });
    attachmentDropArea.addEventListener('dragleave', function () {
        attachmentDropArea.classList.remove('dragover');
    });

    // Handle dropped files by assigning them to the real input
    // via DataTransfer so the browser keeps ownership of the list.
    attachmentDropArea.addEventListener('drop', function (e) {
        attachmentDropArea.classList.remove('dragover');

        const droppedFiles = e.dataTransfer.files;
        if (!droppedFiles.length) return;

        // Merge dropped files with any already selected files
        const dt = new DataTransfer();

        // Keep existing files
        Array.from(attachmentInput.files).forEach(function (f) {
            dt.items.add(f);
        });

        // Add new dropped files (skip duplicates by name+size)
        Array.from(droppedFiles).forEach(function (f) {
            const isDuplicate = Array.from(attachmentInput.files).some(
                function (existing) {
                    return existing.name === f.name && existing.size === f.size;
                }
            );
            if (!isDuplicate) {
                if (f.size > 10 * 1024 * 1024) {
                    alert('File "' + f.name + '" exceeds the 10MB limit.');
                } else {
                    dt.items.add(f);
                }
            }
        });

        // Assign back — this works here because WE created the
        // DataTransfer, so the browser accepts the assignment.
        attachmentInput.files = dt.files;
        updateFileList(Array.from(attachmentInput.files));
    });

    // --------------------------------------------------------
    // Render the visual file preview list below the drop area.
    // This is display-only — submission uses input.files directly.
    // --------------------------------------------------------
    function updateFileList(files) {
        if (files.length > 0) {
            attachmentDropArea.classList.add('hide');
            fileList.classList.add('show');
            fileList.innerHTML = '';

            files.forEach(function (file, index) {
                var iconClass = 'fas fa-file';
                if (file.type.startsWith('image/')) {
                    iconClass = 'fas fa-file-image';
                } else if (file.type === 'application/pdf') {
                    iconClass = 'fas fa-file-pdf';
                } else if (file.type.includes('word') || file.type.includes('document')) {
                    iconClass = 'fas fa-file-word';
                }

                var fileItem = document.createElement('div');
                fileItem.className = 'file-item';
                fileItem.innerHTML =
                    '<i class="' + iconClass + ' file-icon"></i>' +
                    '<div class="file-name">' + file.name + ' (' + formatFileSize(file.size) + ')</div>' +
                    '<button type="button" class="file-remove" data-index="' + index + '">' +
                    '<i class="fas fa-times"></i></button>';
                fileList.appendChild(fileItem);
            });

            // Remove button — rebuilds input.files without that file
            document.querySelectorAll('.file-remove').forEach(function (btn) {
                btn.addEventListener('click', function () {
                    var idx = parseInt(this.getAttribute('data-index'));
                    var dt = new DataTransfer();
                    Array.from(attachmentInput.files).forEach(function (f, i) {
                        if (i !== idx) dt.items.add(f);
                    });
                    attachmentInput.files = dt.files;
                    updateFileList(Array.from(attachmentInput.files));
                });
            });

        } else {
            // No files selected — show the drop area again
            attachmentDropArea.classList.remove('hide');
            fileList.classList.remove('show');
            fileList.innerHTML = '';
        }
    }

    function formatFileSize(bytes) {
        if (bytes === 0) return '0 Bytes';
        var k = 1024;
        var sizes = ['Bytes', 'KB', 'MB', 'GB'];
        var i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    }

});
